  () =>
    import(
      '@/pages/MonthlyInspection/MonthlyInspection/components/InspectionForm'
    ),
)
const InspectionFormView = React.lazy(
  () =>
    import(
      '@/pages/MonthlyInspection/MonthlyInspection/components/InspectionFormView'
    ),
)
//Permit To Work
const PermitToWork = React.lazy(
  () => import('@/pages/PermitToWork/PermitToWorkList'),
)

const PermitToWorkNewRequest = React.lazy(
  () => import('@/pages/PermitToWork/PermitToWorkNewRequest'),
)

const PermitToWorkDetail = React.lazy(
  () => import('@/pages/PermitToWork/PermitToWorkDetail'),
)

// Employee Violations
const EmployeeViolations = React.lazy(
  () => import('@/pages/EmployeeViolations'),
)

// Security Patrol
const SecurityPatrolRecords = React.lazy(
  () => import('@/pages/SecurityPatrol/PatrolRecords'),
)
const SecurityPatrolRecordDetail = React.lazy(
  () =>
    import(
      '@/pages/SecurityPatrol/PatrolRecords/components/PatrolRecordDetail'
    ),
)
const SecurityPatrolContractorManagement = React.lazy(
  () => import('@/pages/SecurityPatrol/ContractorManagement'),
)
