        path: '/contractor/list',
        name: 'Contractor List',
        element: lazyComponent(<PatrolRecord />),
      },
      {
        path: '/contractor/addOrEdit/:id?',
        name: 'Add/Edit Contractor',
        hideInMenu: true,
        element: lazyComponent(<PatrolRecordAddOrEdit />),
      },
      {
        path: '/contractor/detail/:id',
        name: 'Contractor Detail',
        hideInMenu: true,
        element: lazyComponent(<PatrolRecordDetail />),
      },
    ],
  },
  {
    path: `/contractor-portal`,
    name: 'Contractor Portal',
    element: lazyComponent(<EmailJump mode='contractorPortal' />),
  },
  {
    path: `/contractor-portal/detail`,
    name: 'Contractor Portal',
    element: lazyComponent(<EmailJump mode='contractorPortalDetail' />),
  },
  {
    path: '/',
    authRoute: true,
    element: <Layout />,
    children: [
      {
        path: '/dashboard',
        name: 'Dashboard',
        element: lazyComponent(<Dashboard />),
        notSubMenu: true,
        iconMirror: true,
        icon: <DashboardIcon className='arco-menu-item-icon' />,
        selectedIcon: <DashboardSelectedIcon className='arco-menu-item-icon' />,
      },
      {
        path: '/emergency-response',
        name: 'Emergency Response',
        icon: <EmergencyResponseIcon className='arco-menu-item-icon' />,
        selectedIcon: (
          <EmergencyResponseIconSelect className='arco-menu-item-icon' />
        ),
        iconMirror: true,
        element: (
          <SubLayout path='/emergency-response' suffix='/emergency-teams' />
        ),
        children: [
