            path: '/emergency-response/emergency-teams',
            name: 'Emergency Teams',
            element: lazyComponent(<EmergencyTeams />),
          },
          {
            path: '/emergency-response/emergency-teams/add',
            name: 'Add Emergency Team',
            hideInMenu: true,
            element: lazyComponent(<EmergencyTeams />),
          },
          {
            path: '/emergency-response/emergency-teams/edit/:teamId',
            name: 'Edit Emergency Team',
            hideInMenu: true,
            element: lazyComponent(<EmergencyTeams />),
          },
          {
            path: '/emergency-response/emergency-response-plan',
            name: 'Emergency Response Plan',
