import { FC } from 'react'
import ContractorHeader from '../Contractor/components/ContractorHeader'
import LoginForm from './components/LoginForm'
import ForgotPasswordForm from './components/ForgotPasswordForm'
import ResetPasswordForm from './components/ResetPasswordForm'
import ResetPasswordSuccessView from './components/ResetPasswordSuccessView'
import './index.less'

export type ContractorLoginMode =
  | 'login'
  | 'forgotPassword'
  | 'forgotPasswordSent'
  | 'resetPassword'
  | 'resetPasswordSuccess'

export interface ContractorLoginProps {
  mode?: ContractorLoginMode
}

const ContractorLoginPage: FC<ContractorLoginProps> = ({ mode = 'login' }) => {
  const renderForm = () => {
    switch (mode) {
      case 'login':
        return <LoginForm />
      case 'forgotPassword':
        return <ForgotPasswordForm />
      case 'resetPassword':
        return <ResetPasswordForm />
      case 'resetPasswordSuccess':
        return <ResetPasswordSuccessView />
      default:
        return null
    }
  }
  return (
    <div className='login-page'>
      <ContractorHeader showUserInfo={false} />
      {renderForm()}
    </div>
  )
}

export default ContractorLoginPage

