import React, { ReactNode } from 'react'
import { Navigate } from 'react-router-dom'
import { Spin } from '@arco-design/web-react'
import type { RoutesType } from '@common/types/route'

import ContractorGuard from '@/routes/ContractorGuard'

// Contractor Auth
const ContractorLogin = React.lazy(() => import('@/pages/Contractor/Login'))

// Contractor
const PatrolRecord = React.lazy(() => import('@/pages/Contractor/PatrolRecord'))
const PatrolRecordAddOrEdit = React.lazy(
  () =>
    import('@/pages/Contractor/PatrolRecord/components/PatrolRecordAddOrEdit'),
)
const PatrolRecordDetail = React.lazy(
  () => import('@/pages/Contractor/PatrolRecord/components/PatrolRecordDetail'),
)

const NoPermission = React.lazy(() => import('@common/components/NoPermission'))
const EmailJump = React.lazy(() => import('@common/pages/EmailJump'))
const NotFound = React.lazy(() => import('@common/pages/NotFound'))

// 解决路由懒加载切换路由时，一闪而过的问题
const lazyComponent = (element: ReactNode) => {
  return <React.Suspense fallback={<Spin />}>{element}</React.Suspense>
}

const routes: RoutesType[] = [
  {
    path: '/',
    element: <Navigate to='/contractor-login' replace />,
  },
  {
    path: '/contractor-login',
    name: 'Contractor Login',
    authRoute: false,
    element: lazyComponent(<ContractorLogin mode={'login'} />),
  },
  {
    path: '/contractor-login/reset-password-sendEmail',
    name: 'Contractor Forgot Password',
    authRoute: false,
    element: lazyComponent(<ContractorLogin mode={'forgotPassword'} />),
  },
  {
    path: 'reset',
    name: 'Contractor Reset Password',
    authRoute: false,
    element: lazyComponent(<ContractorLogin mode={'resetPassword'} />),
  },
  {
    path: '/contractor-login/reset-password-success',
    name: 'Contractor Reset Password Success',
    authRoute: false,
    element: lazyComponent(<ContractorLogin mode={'resetPasswordSuccess'} />),
  },
  {
    path: '/contractor',
    name: 'Contractor List',
    element: <ContractorGuard />,
    children: [
      {
        path: '/contractor/list',
        name: 'Contractor List',
        element: lazyComponent(<PatrolRecord />),
      },
      {
        path: '/contractor/addOrEdit/:id?',
        name: 'Add/Edit Contractor',
        hideInMenu: true,
        element: lazyComponent(<PatrolRecordAddOrEdit />),
      },
      {
        path: '/contractor/detail/:id',
        name: 'Contractor Detail',
        hideInMenu: true,
        element: lazyComponent(<PatrolRecordDetail />),
      },
    ],
  },
  {
    path: `/contractor-portal`,
    name: 'Contractor Portal',
    element: lazyComponent(<EmailJump mode='contractorPortal' />),
  },
  {
    path: `/contractor-portal/detail`,
    name: 'Contractor Portal Detail',
    element: lazyComponent(<EmailJump mode='contractorPortalDetail' />),
  },
  {
    path: '/403',
    authRoute: false,
    element: lazyComponent(<NoPermission />),
  },
  {
    path: '*',
    authRoute: false,
    element: lazyComponent(<NotFound />),
  },
].filter(Boolean)

export default routes

