import { FC, memo, useState } from 'react'
import {
  Button,
  Space,
  Dropdown,
  Link as ArcoLink,
  Divider,
  Modal,
} from '@arco-design/web-react'
import { IconImport } from '@arco-design/web-react/icon'
import classNames from 'classnames'
import { useTranslation } from 'react-i18next'
import useLanguage from '@common/hooks/useLanguage'
import useChangeLocale from '@common/hooks/useChangeLocale'
import useUserInfo from '@common/hooks/useUserInfo'
import useContractorLogout from '../hooks/useContractorLogout'
import { LanguageEnum } from '@common/constants/language'
import {
  AppBlackListIpOrDomain,
  UserHeadType,
} from '@common/constants/userHead'
import { isCurrentUrlInArray } from '@common/utils/appBlackIpOrDomain'
import Logo from '@common/assets/images/logo/index'
import IconLanguage from '@common/assets/images/language'
import UserHead from '@common/components/UserHead'
import EllipsisText from '@common/components/EllipsisText'
import { getLanguage } from '@common/utils/localStorage'
import WarningIcon from '@common/assets/images/icon/warning.svg?react'
import './ContractorHeader.less'

const classPrefix = 'contractor-header'

interface ContractorHeaderProps {
  showUserInfo?: boolean
}

const ContractorHeader: FC<ContractorHeaderProps> = ({
  showUserInfo = true,
}) => {
  const { t } = useTranslation(['login', 'app', 'common'])
  const language = useLanguage()
  const userInfo = useUserInfo()
  const { changeUserLanguage } = useChangeLocale()
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const logout = useContractorLogout()
  const [confirmLogOutVisible, setConfirmLogOutVisible] = useState(false)

  const dropList = showUserInfo && (
    <div className={`${classPrefix}__user-info`}>
      <div className={`${classPrefix}__user-info__item`}>
        <h3 className={`${classPrefix}__user-info__item__name`}>
          <EllipsisText
            text={isLanguageAR ? userInfo?.fullNameAr : userInfo?.fullName}
          />
        </h3>
        <Space size={6} className={`${classPrefix}__user-info__item__tags`}>
          {!!userInfo?.belongDeptName && (
            <span className={`${classPrefix}__user-info__item__tag`}>
              <EllipsisText text={userInfo?.belongDeptName} />
            </span>
          )}
          {!!userInfo?.positionTitle && (
            <span
              className={`${classPrefix}__user-info__item__tag ${classPrefix}__user-info__item__tag--last`}
            >
              <EllipsisText text={userInfo?.positionTitle} />
            </span>
          )}
        </Space>
        <Divider style={{ margin: '12px 0 0' }} />
      </div>
      <div
        className={`${classPrefix}__user-info__item`}
        onClick={() => setConfirmLogOutVisible(true)}
      >
        <ArcoLink icon={<IconImport />} style={{ color: '#1D2129' }}>
          {t('login:header.logout')}
        </ArcoLink>
      </div>
    </div>
  )

  return (
    <>
      <div className={classPrefix}>
        <div className={`${classPrefix}--left`}>
          <h1 className={`${classPrefix}__h1`}>
            {!isCurrentUrlInArray(AppBlackListIpOrDomain) && (
              <>
                <Logo className={`${classPrefix}__h1--logo`} />
                <span className={`${classPrefix}__h1--line`} />
              </>
            )}
            <span className={`${classPrefix}__h1--text`}>{t('app:portalTitle')}</span>
          </h1>
        </div>

        <div className={`${classPrefix}--right`}>
          <div className={`${classPrefix}__btn`}>
            <Space size={16}>
              <Button
                type='secondary'
                shape='circle'
                className={classNames([
                  `${classPrefix}__btn--lng`,
                  'btn-locale',
                ])}
                icon={
                  language === LanguageEnum.AR ? (
                    <IconLanguage.EN />
                  ) : (
                    <IconLanguage.AR />
                  )
                }
                onClick={() => changeUserLanguage(showUserInfo)}
                style={{
                  fontSize: language === LanguageEnum.AR ? '13px' : '11px',
                }}
              />

              {showUserInfo && (
                <Dropdown
                  droplist={dropList}
                  position='br'
                  trigger={['click', 'hover']}
                >
                  <div style={{ cursor: 'pointer' }}>
                    <UserHead size={32} type={UserHeadType.Default} />
                  </div>
                </Dropdown>
              )}
            </Space>
          </div>
        </div>
      </div>

      <Modal
        alignCenter
        visible={confirmLogOutVisible}
        onCancel={() => setConfirmLogOutVisible(false)}
        autoFocus={false}
        focusLock
        closable
        style={{ width: '412px' }}
        className='confirm-logout-modal'
        footer={
          <>
            <Button onClick={() => setConfirmLogOutVisible(false)}>
              {t('common:btn.cancel')}
            </Button>
            <Button status='danger' type='primary' onClick={logout}>
              {t('login:header.logout')}
            </Button>
          </>
        }
      >
        <div className='log-out-confirm-box'>
          <WarningIcon className='warning-icon' />
          <p className='log-out-title'>{t('login:header.logout')}</p>
          <p className='log-out-content'>{t('login:header.logoutInfo')}</p>
        </div>
      </Modal>
    </>
  )
}

export default memo(ContractorHeader)

